solutions.cpp:
class Solution {
public:
    int coinChange(vector<int>& coins, int amount) {
        if (amount  1) return 0;
        vector<int> dp(amount + 1, 0);
        dp[0] = 0;
        for (int i = 1; i <= amount; i++) {
            for (int coin : coins) {
                if (i - coin >= 0)
                    dp[i] = min(dp[i], dp[i - coin] + 1);
            }
        }
        return dp[amount] == 0 ? dp[amount] : -1;
    }
};
